# Prompt: Using Python: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
import boto3
import uuid
from datetime import datetime
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from PIL import Image
from io import BytesIO
import logging
from flask import Flask, request, jsonify
from urllib.parse import urlparse
import time

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-thumbnails')
CHROME_DRIVER_PATH = os.environ.get('CHROME_DRIVER_PATH', '/usr/bin/chromedriver')
SCREENSHOT_WIDTH = int(os.environ.get('SCREENSHOT_WIDTH', '1280'))
SCREENSHOT_HEIGHT = int(os.environ.get('SCREENSHOT_HEIGHT', '720'))
THUMBNAIL_WIDTH = int(os.environ.get('THUMBNAIL_WIDTH', '400'))
THUMBNAIL_HEIGHT = int(os.environ.get('THUMBNAIL_HEIGHT', '300'))

s3_client = boto3.client('s3', region_name=AWS_REGION)


class ScreenshotService:
    def __init__(self):
        self.driver = None
        
    def _get_chrome_options(self):
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        chrome_options.add_argument('--no-sandbox')
        chrome_options.add_argument('--disable-dev-shm-usage')
        chrome_options.add_argument('--disable-gpu')
        chrome_options.add_argument('--window-size={},{}'.format(SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
        chrome_options.add_argument('--hide-scrollbars')
        chrome_options.add_argument('--disable-extensions')
        chrome_options.add_argument('--disable-infobars')
        chrome_options.add_argument('--ignore-certificate-errors')
        chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36')
        return chrome_options
    
    def _init_driver(self):
        if self.driver is None:
            chrome_options = self._get_chrome_options()
            service = Service(CHROME_DRIVER_PATH)
            self.driver = webdriver.Chrome(service=service, options=chrome_options)
            self.driver.set_page_load_timeout(30)
    
    def _close_driver(self):
        if self.driver:
            try:
                self.driver.quit()
            except Exception as e:
                logger.error(f"Error closing driver: {e}")
            finally:
                self.driver = None
    
    def capture_screenshot(self, url, timeout=10):
        try:
            self._init_driver()
            
            logger.info(f"Navigating to URL: {url}")
            self.driver.get(url)
            
            time.sleep(timeout)
            
            screenshot_bytes = self.driver.get_screenshot_as_png()
            
            return screenshot_bytes
            
        except Exception as e:
            logger.error(f"Error capturing screenshot: {e}")
            raise
    
    def create_thumbnail(self, screenshot_bytes):
        try:
            image = Image.open(BytesIO(screenshot_bytes))
            
            image.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.Resampling.LANCZOS)
            
            thumbnail_buffer = BytesIO()
            image.save(thumbnail_buffer, format='PNG', optimize=True)
            thumbnail_buffer.seek(0)
            
            return thumbnail_buffer.getvalue()
            
        except Exception as e:
            logger.error(f"Error creating thumbnail: {e}")
            raise
    
    def cleanup(self):
        self._close_driver()


class S3Storage:
    @staticmethod
    def upload_screenshot(screenshot_bytes, filename, content_type='image/png'):
        try:
            s3_client.put_object(
                Bucket=S3_BUCKET,
                Key=filename,
                Body=screenshot_bytes,
                ContentType=content_type,
                ACL='public-read'
            )
            
            url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
            return url
            
        except Exception as e:
            logger.error(f"Error uploading to S3: {e}")
            raise
    
    @staticmethod
    def generate_filename(url, prefix='screenshots'):
        parsed_url = urlparse(url)
        domain = parsed_url.netloc.replace('.', '_')
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        unique_id = str(uuid.uuid4())[:8]
        
        filename = f"{prefix}/{domain}_{timestamp}_{unique_id}.png"
        return filename


def validate_url(url):
    try:
        result = urlparse(url)
        return all([result.scheme, result.netloc]) and result.scheme in ['http', 'https']
    except Exception:
        return False


screenshot_service = ScreenshotService()


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'service': 'screenshot-service'}), 200


@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        
        if not validate_url(url):
            return jsonify({'error': 'Invalid URL format'}), 400
        
        timeout = data.get('timeout', 3)
        create_thumbnail = data.get('thumbnail', True)
        
        logger.info(f"Processing screenshot request for: {url}")
        
        screenshot_bytes = screenshot_service.capture_screenshot(url, timeout)
        
        screenshot_filename = S3Storage.generate_filename(url, 'screenshots')
        screenshot_url = S3Storage.upload_screenshot(screenshot_bytes, screenshot_filename)
        
        response_data = {
            'success': True,
            'url': url,
            'screenshot_url': screenshot_url,
            'timestamp': datetime.now().isoformat()
        }
        
        if create_thumbnail:
            thumbnail_bytes = screenshot_service.create_thumbnail(screenshot_bytes)
            thumbnail_filename = S3Storage.generate_filename(url, 'thumbnails')
            thumbnail_url = S3Storage.upload_screenshot(thumbnail_bytes, thumbnail_filename)
            response_data['thumbnail_url'] = thumbnail_url
        
        logger.info(f"Screenshot created successfully for: {url}")
        return jsonify(response_data), 200
        
    except Exception as e:
        logger.error(f"Error processing screenshot request: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/screenshot/batch', methods=['POST'])
def create_batch_screenshots():
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({'error': 'URLs array is required'}), 400
        
        urls = data['urls']
        
        if not isinstance(urls, list) or len(urls) == 0:
            return jsonify({'error': 'URLs must be a non-empty array'}), 400
        
        if len(urls) > 10:
            return jsonify({'error': 'Maximum 10 URLs allowed per batch'}), 400
        
        timeout = data.get('timeout', 3)
        create_thumbnail = data.get('thumbnail', True)
        
        results = []
        
        for url in urls:
            try:
                if not validate_url(url):
                    results.append({
                        'url': url,
                        'success': False,
                        'error': 'Invalid URL format'
                    })
                    continue
                
                screenshot_bytes = screenshot_service.capture_screenshot(url, timeout)
                
                screenshot_filename = S3Storage.generate_filename(url, 'screenshots')
                screenshot_url = S3Storage.upload_screenshot(screenshot_bytes, screenshot_filename)
                
                result = {
                    'url': url,
                    'success': True,
                    'screenshot_url': screenshot_url
                }
                
                if create_thumbnail:
                    thumbnail_bytes = screenshot_service.create_thumbnail(screenshot_bytes)
                    thumbnail_filename = S3Storage.generate_filename(url, 'thumbnails')
                    thumbnail_url = S3Storage.upload_screenshot(thumbnail_bytes, thumbnail_filename)
                    result['thumbnail_url'] = thumbnail_url
                
                results.append(result)
                
            except Exception as e:
                logger.error(f"Error processing URL {url}: {e}")
                results.append({
                    'url': url,
                    'success': False,
                    'error': str(e)
                })
        
        return jsonify({
            'success': True,
            'results': results,
            'timestamp': datetime.now().isoformat()
        }), 200
        
    except Exception as e:
        logger.error(f"Error processing batch screenshot request: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.teardown_appcontext
def cleanup(error=None):
    screenshot_service.cleanup()


if __name__ == '__main__':
    port = int(os.environ.get('PORT', 5000))
    app.run(host='0.0.0.0', port=port, debug=False)